14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
17	
18	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
19	
20	const componentBlockBaseFor = (count: number, type: string): number =>
21	  count === BLOCK_SIZE
22	    ? BLOCK_PRICE
23	    : count * BASE_PREMIUM_BY_ITEM_TYPE[type];
24	
25	const countBy = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> =>
26	  values.reduce((counts, value) => {
27	    const key = keyOf(value);
28	    counts.set(key, (counts.get(key) ?? 0) + 1);
29	    return counts;
30	  }, new Map<string, number>());
31	
32	const countByType = (items: Item[]): Map<string, number> =>
33	  countBy(items, (item) => item.type);
34	
35	const componentsBaseFor = (items: Item[]): number => {
36	  const countsByType = countByType(items);
37	  return Array.from(countsByType).reduce(
38	    (total, [type, count]) => total + componentBlockBaseFor(count, type),
39	    0
40	  );
41	};
