132	export function quote(input: {
133	  yearsWithMHPCO: number;
134	  items: Item[];
135	  applyFirstInsurance?: boolean;
136	  applyFollowUpDiscount?: boolean;
137	}): number {
138	  for (const item of input.items) {
139	    if (!(item.type in BASE_PREMIUM_BY_ITEM_TYPE)) {
140	      throw new Error(`Unknown item type: ${item.type}`);
141	    }
142	  }
143	  const policyBase = policyBaseFor(input.items);
144	  const itemBasesSum = sumOfItemBases(input.items);
145	  return Math.ceil(
146	    policyBase
147	    + firstInsuranceSurchargeFor(input.applyFirstInsurance, input.items)
148	    - loyaltyDiscountFor(input.yearsWithMHPCO, itemBasesSum)
149	    - followUpDiscountFor(input.applyFollowUpDiscount, itemBasesSum)
150	    + PROCESSING_FEE
151	  );
152	}
